"use client";

// app/project-hub/part-tracking/page.tsximport Link from "next/link";
import { useState, FormEvent } from "react";
import PageShell from "@/components/layout/PageShell";

type Stage =
  | "Kick-off"
  | "Tasarım"
  | "Numune"
  | "PPAP"
  | "SOP";

type RiskFlag = "Yok" | "Orta" | "Yüksek";

type PartRow = {
  id: number;
  customer: string;
  projectCode: string;
  partCode: string;
  partName: string;
  stage: Stage;
  ppapStatus: string;
  sopDate: string;
  risk: RiskFlag;
  notes: string;
};

type StageFilter = "all" | Stage;

let nextId = 1;

export default function PartTrackingPage() {
  const [rows, setRows] = useState<PartRow[]>([]);
  const [stageFilter, setStageFilter] = useState<StageFilter>("all");

  const [form, setForm] = useState({
    customer: "",
    projectCode: "",
    partCode: "",
    partName: "",
    stage: "Kick-off" as Stage,
    ppapStatus: "",
    sopDate: "",
    risk: "Yok" as RiskFlag,
    notes: "",
  });

  const [error, setError] = useState<string | null>(null);

  function handleChange<K extends keyof typeof form>(
    key: K,
    value: (typeof form)[K],
  ) {
    setForm((prev) => ({ ...prev, [key]: value }));
  }

  function handleAdd(e: FormEvent) {
    e.preventDefault();
    setError(null);

    if (!form.customer || !form.projectCode || !form.partCode || !form.partName) {
      setError("Müşteri, Proje Kodu, Parça Kodu ve Parça Adı alanları zorunludur.");
      return;
    }

    const newRow: PartRow = {
      id: nextId++,
      customer: form.customer,
      projectCode: form.projectCode,
      partCode: form.partCode,
      partName: form.partName,
      stage: form.stage,
      ppapStatus: form.ppapStatus,
      sopDate: form.sopDate,
      risk: form.risk,
      notes: form.notes,
    };

    setRows((prev) => [newRow, ...prev]);

    setForm((prev) => ({
      ...prev,
      partCode: "",
      partName: "",
      ppapStatus: "",
      sopDate: "",
      notes: "",
    }));
  }

  function handleDelete(id: number) {
    setRows((prev) => prev.filter((r) => r.id !== id));
  }

  function handleStageQuickChange(id: number, stage: Stage) {
    setRows((prev) =>
      prev.map((r) => (r.id === id ? { ...r, stage } : r)),
    );
  }

  const filteredRows =
    stageFilter === "all"
      ? rows
      : rows.filter((r) => r.stage === stageFilter);

  // Basit istatistikler
  const total = rows.length;
  const byStageCount: Record<Stage, number> = {
    "Kick-off": rows.filter((r) => r.stage === "Kick-off").length,
    "Tasarım": rows.filter((r) => r.stage === "Tasarım").length,
    "Numune": rows.filter((r) => r.stage === "Numune").length,
    "PPAP": rows.filter((r) => r.stage === "PPAP").length,
    "SOP": rows.filter((r) => r.stage === "SOP").length,
  };

  return (
    <PageShell>
      {/* Başlık */}
      <section className="rounded-2xl border border-slate-200 bg-white p-5 shadow-sm">
        <div className="mb-3 flex items-center gap-2">
          <span className="rounded-full bg-slate-900 px-3 py-1 text-[10px] font-semibold uppercase tracking-wide text-white">
            Proje Mühendisleri Alanı
          </span>
          <span className="rounded-full bg-slate-100 px-3 py-1 text-[10px] font-medium text-slate-600">
            Parça Durumu Takip Panosu
          </span>
        </div>

        <h1 className="text-lg font-semibold text-slate-900">
          Parça Durumu Takip Panosu
        </h1>
        <p className="mt-2 text-xs text-slate-600">
          Kick-off&apos;tan SOP&apos;a kadar proje parçalarının durumunu takip etmek için hafif bir dashboard. Aşamalar:
          Kick-off, Tasarım, Numune, PPAP, SOP. Girdiğin satırlar bu sayfada tutulur. Dışa aktarma (PDF/Excel) premium
          paketinin özel beta kapsamındadır. Erken erişim için{" "}
          <Link href="/pricing" className="font-semibold text-amber-700 hover:underline">
            ücretlendirmeye göz at
          </Link>.
        </p>
      </section>

      {/* İstatistik + Form + Liste */}
      <section className="space-y-4">
        {/* Küçük özet kutuları */}
        <div className="grid gap-3 sm:grid-cols-3 lg:grid-cols-5">
          <MiniStat label="Toplam parça" value={total.toString()} />
          <MiniStat label="Kick-off" value={byStageCount["Kick-off"].toString()} />
          <MiniStat label="Tasarım" value={byStageCount["Tasarım"].toString()} />
          <MiniStat label="Numune" value={byStageCount["Numune"].toString()} />
          <MiniStat label="PPAP / SOP" value={(byStageCount["PPAP"] + byStageCount["SOP"]).toString()} />
        </div>

        {/* Form + Liste */}
        <div className="grid gap-4 lg:grid-cols-[minmax(0,1.4fr)_minmax(0,1.3fr)]">
          {/* Sol: form */}
          <div className="rounded-2xl border border-slate-200 bg-white p-5 text-xs shadow-sm">
            <h2 className="mb-3 text-sm font-semibold text-slate-900">
              Yeni Parça Kaydı
            </h2>

            <form className="space-y-3" onSubmit={handleAdd}>
              <div className="grid gap-2 sm:grid-cols-2">
                <div className="space-y-1">
                  <label className="block text-[11px] font-medium text-slate-700">
                    Müşteri
                  </label>
                  <input
                    type="text"
                    value={form.customer}
                    onChange={(e) => handleChange("customer", e.target.value)}
                    className="w-full rounded-lg border border-slate-300 px-2 py-1.5 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
                    placeholder="Örn. OEM X"
                   aria-label="Örn. OEM X"/>
                </div>

                <div className="space-y-1">
                  <label className="block text-[11px] font-medium text-slate-700">
                    Proje Kodu
                  </label>
                  <input
                    type="text"
                    value={form.projectCode}
                    onChange={(e) =>
                      handleChange("projectCode", e.target.value)
                    }
                    className="w-full rounded-lg border border-slate-300 px-2 py-1.5 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
                    placeholder="Örn. P-2025-01"
                   aria-label="Örn. P-2025-01"/>
                </div>
              </div>

              <div className="grid gap-2 sm:grid-cols-2">
                <div className="space-y-1">
                  <label className="block text-[11px] font-medium text-slate-700">
                    Parça Kodu
                  </label>
                  <input
                    type="text"
                    value={form.partCode}
                    onChange={(e) => handleChange("partCode", e.target.value)}
                    className="w-full rounded-lg border border-slate-300 px-2 py-1.5 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
                    placeholder="Örn. 1234-567-890"
                   aria-label="Örn. 1234-567-890"/>
                </div>

                <div className="space-y-1">
                  <label className="block text-[11px] font-medium text-slate-700">
                    Parça Adı
                  </label>
                  <input
                    type="text"
                    value={form.partName}
                    onChange={(e) => handleChange("partName", e.target.value)}
                    className="w-full rounded-lg border border-slate-300 px-2 py-1.5 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
                    placeholder="Örn. Ön amortisör üst braketi"
                   aria-label="Örn. Ön amortisör üst braketi"/>
                </div>
              </div>

              <div className="grid gap-2 sm:grid-cols-3">
                <div className="space-y-1">
                  <label className="block text-[11px] font-medium text-slate-700">
                    Aşama
                  </label>
                  <select
                    value={form.stage}
                    onChange={(e) =>
                      handleChange("stage", e.target.value as Stage)
                    }
                    className="w-full rounded-lg border border-slate-300 px-2 py-1.5 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
                   aria-label="Select field">
                    <option>Kick-off</option>
                    <option>Tasarım</option>
                    <option>Numune</option>
                    <option>PPAP</option>
                    <option>SOP</option>
                  </select>
                </div>

                <div className="space-y-1">
                  <label className="block text-[11px] font-medium text-slate-700">
                    PPAP Durumu
                  </label>
                  <input
                    type="text"
                    value={form.ppapStatus}
                    onChange={(e) =>
                      handleChange("ppapStatus", e.target.value)
                    }
                    className="w-full rounded-lg border border-slate-300 px-2 py-1.5 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
                    placeholder="Örn. PPAP level 3, beklemede"
                   aria-label="Örn. PPAP level 3, beklemede"/>
                </div>

                <div className="space-y-1">
                  <label className="block text-[11px] font-medium text-slate-700">
                    Hedef SOP tarihi
                  </label>
                  <input
                    type="date"
                    value={form.sopDate}
                    onChange={(e) => handleChange("sopDate", e.target.value)}
                    className="w-full rounded-lg border border-slate-300 px-2 py-1.5 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
                   aria-label="Date input"/>
                </div>
              </div>

              <div className="space-y-1">
                <label className="block text-[11px] font-medium text-slate-700">
                  Risk seviyesi
                </label>
                <select
                  value={form.risk}
                  onChange={(e) =>
                    handleChange("risk", e.target.value as RiskFlag)
                  }
                  className="w-full rounded-lg border border-slate-300 px-2 py-1.5 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
                 aria-label="Select field">
                  <option>Yok</option>
                  <option>Orta</option>
                  <option>Yüksek</option>
                </select>
              </div>

              <div className="space-y-1">
                <label className="block text-[11px] font-medium text-slate-700">
                  Notlar
                </label>
                <textarea
                  value={form.notes}
                  onChange={(e) => handleChange("notes", e.target.value)}
                  rows={3}
                  className="w-full rounded-lg border border-slate-300 px-2 py-1.5 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
                  placeholder="Örn. Tedarikçi riski, kalite açık aksiyonları, müşteri özel isteği..."
                 aria-label="Örn. Tedarikçi riski, kalite açık aksiyonları, müşteri özel isteği..."/>
              </div>

              {error && (
                <p className="text-[11px] text-red-600">
                  {error}
                </p>
              )}

              <button
                type="submit"
                className="mt-2 inline-flex items-center rounded-full bg-slate-900 px-4 py-1.5 text-[11px] font-semibold text-white hover:bg-slate-800"
              >
                Parça ekle
              </button>
            </form>
          </div>

          {/* Sağ: liste + filtre */}
          <div className="rounded-2xl border border-slate-200 bg-white p-5 text-xs shadow-sm">
            <div className="mb-3 flex items-center justify-between gap-2">
              <h2 className="text-sm font-semibold text-slate-900">
                Parça Listesi
              </h2>
              <StageFilterChips value={stageFilter} onChange={setStageFilter} />
            </div>

            {filteredRows.length === 0 ? (
              <p className="text-[11px] text-slate-500">
                Henüz kayıt yok veya seçili aşamaya uygun parça bulunamadı.
              </p>
            ) : (
              <div className="max-h-80 space-y-2 overflow-auto pr-1">
                {filteredRows.map((row) => (
                  <div
                    key={row.id}
                    className="rounded-xl border border-slate-200 bg-slate-50 px-3 py-2"
                  >
                    <div className="mb-1 flex items-center justify-between gap-2">
                      <div className="flex flex-col">
                        <span className="text-[11px] font-semibold text-slate-900">
                          {row.customer} – {row.projectCode}
                        </span>
                        <span className="text-[11px] text-slate-600">
                          {row.partCode} – {row.partName}
                        </span>
                      </div>
                      <span className="rounded-full bg-slate-900 px-2 py-0.5 text-[10px] font-semibold text-white">
                        {row.stage}
                      </span>
                    </div>

                    <div className="mb-1 flex flex-wrap gap-x-3 gap-y-1 text-[11px] text-slate-600">
                      {row.ppapStatus && <span>PPAP: {row.ppapStatus}</span>}
                      {row.sopDate && (
                        <span>
                          SOP:{" "}
                          {new Date(row.sopDate).toLocaleDateString("tr-TR")}
                        </span>
                      )}
                      <span>
                        Risk:{" "}
                        {row.risk === "Yüksek" ? "⚠️ Yüksek" : row.risk}
                      </span>
                    </div>

                    {row.notes && (
                      <p className="text-[11px] text-slate-600">
                        Not: {row.notes}
                      </p>
                    )}

                    <div className="mt-2 flex items-center justify-between gap-2">
                      <div className="flex flex-wrap gap-1">
                        {/* Hızlı aşama geçiş butonları */}
                        <QuickStageButton
                          label="Tasarım"
                          onClick={() => handleStageQuickChange(row.id, "Tasarım")}
                        />
                        <QuickStageButton
                          label="Numune"
                          onClick={() => handleStageQuickChange(row.id, "Numune")}
                        />
                        <QuickStageButton
                          label="PPAP"
                          onClick={() => handleStageQuickChange(row.id, "PPAP")}
                        />
                        <QuickStageButton
                          label="SOP"
                          onClick={() => handleStageQuickChange(row.id, "SOP")}
                        />
                      </div>

                      <button
                        type="button"
                        onClick={() => handleDelete(row.id)}
                        className="text-[11px] text-red-600 hover:underline"
                      >
                        Sil
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </section>
    </PageShell>
  );
}

type MiniStatProps = {
  label: string;
  value: string;
};

function MiniStat({ label, value }: MiniStatProps) {
  return (
    <div className="rounded-2xl border border-slate-200 bg-white px-3 py-2 text-xs shadow-sm">
      <p className="text-[11px] text-slate-500">{label}</p>
      <p className="text-base font-semibold text-slate-900">{value}</p>
    </div>
  );
}

type StageFilterChipsProps = {
  value: StageFilter;
  onChange: (v: StageFilter) => void;
};

function StageFilterChips({ value, onChange }: StageFilterChipsProps) {
  const options: { value: StageFilter; label: string }[] = [
    { value: "all", label: "Tümü" },
    { value: "Kick-off", label: "Kick-off" },
    { value: "Tasarım", label: "Tasarım" },
    { value: "Numune", label: "Numune" },
    { value: "PPAP", label: "PPAP" },
    { value: "SOP", label: "SOP" },
  ];

  return (
    <div className="inline-flex flex-wrap gap-1">
      {options.map((opt) => (
        <button
          key={opt.value}
          type="button"
          onClick={() => onChange(opt.value)}
          className={`rounded-full border px-2.5 py-1 text-[10px] font-medium ${
            value === opt.value
              ? "border-slate-900 bg-slate-900 text-white"
              : "border-slate-300 bg-white text-slate-700 hover:border-slate-400 hover:bg-slate-50"
          }`}
        >
          {opt.label}
        </button>
      ))}
    </div>
  );
}

type QuickStageButtonProps = {
  label: Stage;
  onClick: () => void;
};

function QuickStageButton({ label, onClick }: QuickStageButtonProps) {
  return (
    <button
      type="button"
      onClick={onClick}
      className="rounded-full border border-slate-300 px-2 py-0.5 text-[10px] text-slate-700 hover:border-slate-400 hover:bg-slate-50"
    >
      {label}
    </button>
  );
}

"use client";

// app/project-hub/project-tools/page.tsximport Link from "next/link";
import {
  useEffect,
  useState,
  ChangeEvent,
  FormEvent,
} from "react";
import type { ReactNode } from "react";
import PageShell from "@/components/layout/PageShell";

type ProjectStatus = "open" | "in-progress" | "blocked" | "done";
type ProjectPriority = "low" | "medium" | "high";

type Project = {
  id: string;
  title: string;
  customer: string;
  lineOrArea: string;
  status: ProjectStatus;
  priority: ProjectPriority;
  dueDate: string;
  notes: string;
};

type Filter = {
  status: "all" | ProjectStatus;
  priority: "all" | ProjectPriority;
};

const STORAGE_KEY = "aiengineerslab-projects-v1";

export default function ProjectToolsPage() {
  const [projects, setProjects] = useState<Project[]>([]);
  const [filter, setFilter] = useState<Filter>({
    status: "all",
    priority: "all",
  });

  const [form, setForm] = useState<Omit<Project, "id">>({
    title: "",
    customer: "",
    lineOrArea: "",
    status: "open",
    priority: "medium",
    dueDate: "",
    notes: "",
  });

  // LocalStorage'dan oku
  useEffect(() => {
    if (typeof window === "undefined") return;
    try {
      const raw = window.localStorage.getItem(STORAGE_KEY);
      if (!raw) return;
      const parsed = JSON.parse(raw) as Project[];
      Promise.resolve().then(() => setProjects(parsed));
    } catch {
      // ignore
    }
  }, []);

  // LocalStorage'a yaz
  useEffect(() => {
    if (typeof window === "undefined") return;
    window.localStorage.setItem(STORAGE_KEY, JSON.stringify(projects));
  }, [projects]);

  function handleFormChange(
    key: keyof Omit<Project, "id">,
    e: ChangeEvent<
      HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement
    >
  ) {
    setForm((prev) => ({ ...prev, [key]: e.target.value }));
  }

  function handleSubmit(e: FormEvent) {
    e.preventDefault();
    if (!form.title.trim()) return;

    const newProject: Project = {
      id:
        typeof crypto !== "undefined" && "randomUUID" in crypto
          ? crypto.randomUUID()
          : `${Date.now()}-${Math.random().toString(16).slice(2)}`,
      ...form,
    };

    setProjects((prev) => [newProject, ...prev]);
    setForm({
      title: "",
      customer: "",
      lineOrArea: "",
      status: "open",
      priority: "medium",
      dueDate: "",
      notes: "",
    });
  }

  function handleFilterChange<K extends keyof Filter>(key: K, value: Filter[K]) {
    setFilter((prev) => ({ ...prev, [key]: value }));
  }

  function toggleStatus(id: string) {
    setProjects((prev) =>
      prev.map((p) =>
        p.id === id
          ? {
              ...p,
              status:
                p.status === "done"
                  ? "open"
                  : p.status === "open"
                  ? "in-progress"
                  : p.status === "in-progress"
                  ? "blocked"
                  : "done",
            }
          : p
      )
    );
  }

  function deleteProject(id: string) {
    if (!confirm("Bu proje kaydını silmek istediğine emin misin?")) return;
    setProjects((prev) => prev.filter((p) => p.id !== id));
  }

  const filteredProjects = projects.filter((p) => {
    if (filter.status !== "all" && p.status !== filter.status) return false;
    if (filter.priority !== "all" && p.priority !== filter.priority) return false;
    return true;
  });

  return (
    <PageShell>
      {/* Başlık */}
      <section className="rounded-2xl border border-slate-200 bg-white p-5 shadow-sm">
        <div className="mb-3 flex items-center gap-2">
          <span className="rounded-full bg-slate-900 px-3 py-1 text-[10px] font-semibold uppercase tracking-wide text-white">
            Proje Mühendisleri Alanı
          </span>
          <span className="rounded-full bg-slate-100 px-3 py-1 text-[10px] font-medium text-slate-600">
            Proje / değişiklik takibi · Hat &amp; proses iyileştirmeleri
          </span>
        </div>

        <h1 className="text-lg font-semibold text-slate-900">
          Proje &amp; İyileştirme Takip Paneli
        </h1>
        <p className="mt-2 text-xs text-slate-600">
          Müşteri projeleri, proses iyileştirmeleri ve Kaizen çalışmalarını tek yerden takip etmek için hafif bir proje
          listesi. Kayıtlar şu an sadece bu tarayıcıda (localStorage) tutuluyor. PDF/Excel çıktı ve çoklu cihaz erişimi
          premium paketinin özel beta kapsamındadır. Erken erişim için{" "}
          <Link href="/pricing" className="font-semibold text-amber-700 hover:underline">
            ücretlendirmeye göz at
          </Link>.
        </p>
      </section>

      {/* Form + Filtreler */}
      <section className="grid gap-4 lg:grid-cols-[minmax(0,1.4fr)_minmax(0,1fr)]">
        {/* Form */}
        <form
          onSubmit={handleSubmit}
          className="rounded-2xl border border-slate-200 bg-white p-5 text-xs shadow-sm space-y-3"
        >
          <div className="flex items-center justify-between gap-2">
            <h2 className="text-sm font-semibold text-slate-900">
              Yeni Proje / İyileştirme Kaydı
            </h2>
            <button
              type="submit"
              className="rounded-full bg-slate-900 px-4 py-1.5 text-[11px] font-semibold text-white hover:bg-slate-800"
            >
              Kaydı Ekle
            </button>
          </div>

          <div className="grid gap-3 md:grid-cols-2">
            <div className="space-y-1 md:col-span-2">
              <label className="block text-[11px] font-medium text-slate-700">
                Proje / Çalışma Başlığı
              </label>
              <input
                type="text"
                value={form.title}
                onChange={(e) => handleFormChange("title", e)}
                className="w-full rounded-lg border border-slate-300 px-2 py-1.5 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
                placeholder="Örn. Ön süspansiyon civata tork dokümanının revizyonu, Hat 2 verimlilik iyileştirmesi..."
                required
               aria-label="Örn. Ön süspansiyon civata tork dokümanının revizyonu, Hat 2 verimlilik iyileştirmesi..."/>
            </div>

            <div className="space-y-1">
              <label className="block text-[11px] font-medium text-slate-700">
                Müşteri / İç Birim
              </label>
              <input
                type="text"
                value={form.customer}
                onChange={(e) => handleFormChange("customer", e)}
                className="w-full rounded-lg border border-slate-300 px-2 py-1.5 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
                placeholder="Örn. OEM A, İç Kalite, Üretim Hat 2..."
               aria-label="Örn. OEM A, İç Kalite, Üretim Hat 2..."/>
            </div>

            <div className="space-y-1">
              <label className="block text-[11px] font-medium text-slate-700">
                Hat / Proses Alanı
              </label>
              <input
                type="text"
                value={form.lineOrArea}
                onChange={(e) => handleFormChange("lineOrArea", e)}
                className="w-full rounded-lg border border-slate-300 px-2 py-1.5 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
                placeholder="Örn. Montaj Hattı 2 - İstasyon 4, CNC işleme..."
               aria-label="Örn. Montaj Hattı 2 - İstasyon 4, CNC işleme..."/>
            </div>

            <div className="space-y-1">
              <label className="block text-[11px] font-medium text-slate-700">
                Durum
              </label>
              <select
                value={form.status}
                onChange={(e) =>
                  handleFormChange(
                    "status",
                    e as unknown as ChangeEvent<HTMLSelectElement>
                  )
                }
                className="w-full rounded-lg border border-slate-300 px-2 py-1.5 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
               aria-label="Select field">
                <option value="open">Açık</option>
                <option value="in-progress">Devam ediyor</option>
                <option value="blocked">Blokaj var</option>
                <option value="done">Tamamlandı</option>
              </select>
            </div>

            <div className="space-y-1">
              <label className="block text-[11px] font-medium text-slate-700">
                Öncelik
              </label>
              <select
                value={form.priority}
                onChange={(e) =>
                  handleFormChange(
                    "priority",
                    e as unknown as ChangeEvent<HTMLSelectElement>
                  )
                }
                className="w-full rounded-lg border border-slate-300 px-2 py-1.5 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
               aria-label="Select field">
                <option value="low">Düşük</option>
                <option value="medium">Orta</option>
                <option value="high">Yüksek</option>
              </select>
            </div>

            <div className="space-y-1">
              <label className="block text-[11px] font-medium text-slate-700">
                Hedef Tamamlanma Tarihi
              </label>
              <input
                type="date"
                value={form.dueDate}
                onChange={(e) => handleFormChange("dueDate", e)}
                className="w-full rounded-lg border border-slate-300 px-2 py-1.5 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
               aria-label="Date input"/>
            </div>

            <div className="space-y-1 md:col-span-2">
              <label className="block text-[11px] font-medium text-slate-700">
                Teknik Notlar / Kapsam
              </label>
              <textarea
                rows={3}
                value={form.notes}
                onChange={(e) => handleFormChange("notes", e)}
                className="w-full rounded-lg border border-slate-300 px-2 py-1.5 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
                placeholder="Örn. Kapsam, kritik parçalar, ilgili doküman kodları, tahmini iş yükü..."
               aria-label="Örn. Kapsam, kritik parçalar, ilgili doküman kodları, tahmini iş yükü..."/>
            </div>
          </div>
        </form>

        {/* Filtreler + not */}
        <aside className="rounded-2xl border border-slate-200 bg-white p-5 text-xs shadow-sm space-y-4">
          <div>
            <h2 className="mb-2 text-sm font-semibold text-slate-900">
              Filtreler
            </h2>
            <div className="space-y-2">
              <div className="space-y-1">
                <p className="text-[11px] font-medium text-slate-700">
                  Duruma göre filtrele
                </p>
                <div className="flex flex-wrap gap-1.5">
                  {[
                    { value: "all", label: "Tümü" },
                    { value: "open", label: "Açık" },
                    { value: "in-progress", label: "Devam" },
                    { value: "blocked", label: "Blokaj" },
                    { value: "done", label: "Tamam" },
                  ].map((item) => (
                    <button
                      key={item.value}
                      type="button"
                      onClick={() =>
                        handleFilterChange(
                          "status",
                          item.value as Filter["status"]
                        )
                      }
                      className={`rounded-full px-3 py-1 text-[11px] border ${
                        filter.status === item.value
                          ? "bg-slate-900 text-white border-slate-900"
                          : "bg-white text-slate-700 border-slate-300"
                      }`}
                    >
                      {item.label}
                    </button>
                  ))}
                </div>
              </div>

              <div className="space-y-1">
                <p className="text-[11px] font-medium text-slate-700">
                  Önceliğe göre filtrele
                </p>
                <div className="flex flex-wrap gap-1.5">
                  {[
                    { value: "all", label: "Tümü" },
                    { value: "high", label: "Yüksek" },
                    { value: "medium", label: "Orta" },
                    { value: "low", label: "Düşük" },
                  ].map((item) => (
                    <button
                      key={item.value}
                      type="button"
                      onClick={() =>
                        handleFilterChange(
                          "priority",
                          item.value as Filter["priority"]
                        )
                      }
                      className={`rounded-full px-3 py-1 text-[11px] border ${
                        filter.priority === item.value
                          ? "bg-slate-900 text-white border-slate-900"
                          : "bg-white text-slate-700 border-slate-300"
                      }`}
                    >
                      {item.label}
                    </button>
                  ))}
                </div>
              </div>
            </div>
          </div>

          <div className="rounded-xl bg-slate-50 p-3 text-[11px] text-slate-600">
            <p className="font-semibold text-slate-900 mb-1">
              Mühendis gözüyle kullanım notu
            </p>
            <p>
              Bu alanı, hem üretim hattı küçük iyileştirmeleri (Kaizen) hem de müşteri projelerinin kritik maddelerini
              takip etmek için kullanabilirsin. İleride her kayıt; 8D, FMEA ve kalite araçlarıyla ilişkilendirilebilir ve
              PDF/Excel çıktı premium paketinin özel beta kapsamındadır. Erken erişim için{" "}
              <Link href="/pricing" className="font-semibold text-amber-700 hover:underline">
                ücretlendirmeye göz at
              </Link>.
            </p>
          </div>
        </aside>
      </section>

      {/* Proje listesi */}
      <section className="rounded-2xl border border-slate-200 bg-white p-5 text-xs shadow-sm">
        <div className="mb-3 flex items-center justify-between gap-2">
          <h2 className="text-sm font-semibold text-slate-900">
            Kayıtlı Projeler / Çalışmalar
          </h2>
          <span className="text-[11px] text-slate-500">
            Toplam: {projects.length} kayıt · Filtrelenen: {filteredProjects.length}
          </span>
        </div>

        {filteredProjects.length === 0 ? (
          <p className="text-[11px] text-slate-500">
            Henüz filtreye uyan bir kayıt yok. Üstteki formdan yeni bir proje
            ekleyebilirsin.
          </p>
        ) : (
          <div className="overflow-x-auto rounded-xl border border-slate-200">
            <table className="min-w-full border-collapse text-[11px]">
              <thead className="bg-slate-50">
                <tr>
                  <Th>Başlık</Th>
                  <Th>Müşteri / Birim</Th>
                  <Th>Hat / Alan</Th>
                  <Th>Durum</Th>
                  <Th>Öncelik</Th>
                  <Th>Hedef Tarih</Th>
                  <Th>Aksiyon</Th>
                </tr>
              </thead>
              <tbody>
                {filteredProjects.map((p) => (
                  <tr
                    key={p.id}
                    className="border-t border-slate-200 hover:bg-slate-50"
                  >
                    <Td className="max-w-xs">
                      <div className="flex flex-col gap-0.5">
                        <span className="font-semibold text-slate-900">
                          {p.title}
                        </span>
                        {p.notes && (
                          <span className="line-clamp-2 text-[10px] text-slate-600">
                            {p.notes}
                          </span>
                        )}
                      </div>
                    </Td>
                    <Td>{p.customer || "-"}</Td>
                    <Td>{p.lineOrArea || "-"}</Td>
                    <Td>
                      <StatusBadge status={p.status} />
                    </Td>
                    <Td>
                      <PriorityBadge priority={p.priority} />
                    </Td>
                    <Td>{p.dueDate || "-"}</Td>
                    <Td>
                      <div className="flex flex-wrap gap-1.5">
                        <button
                          type="button"
                          onClick={() => toggleStatus(p.id)}
                          className="rounded-full border border-slate-300 px-2 py-0.5 text-[10px] text-slate-700 hover:bg-slate-100"
                        >
                          Durum Değiştir
                        </button>
                        <button
                          type="button"
                          onClick={() => deleteProject(p.id)}
                          className="rounded-full border border-rose-200 bg-rose-50 px-2 py-0.5 text-[10px] text-rose-700 hover:bg-rose-100"
                        >
                          Sil
                        </button>
                      </div>
                    </Td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </section>
    </PageShell>
  );
}

/* Küçük yardımcı bileşenler */

function Th({ children }: { children: ReactNode }) {
  return (
    <th className="border-b border-slate-200 px-3 py-2 text-left font-semibold text-slate-700">
      {children}
    </th>
  );
}

function Td({
  children,
  className = "",
}: {
  children: ReactNode;
  className?: string;
}) {
  return (
    <td className={`px-3 py-2 align-top text-slate-700 ${className}`}>
      {children}
    </td>
  );
}

function StatusBadge({ status }: { status: ProjectStatus }) {
  const map: Record<ProjectStatus, { label: string; className: string }> = {
    open: {
      label: "Açık",
      className: "bg-slate-100 text-slate-800 border border-slate-200",
    },
    "in-progress": {
      label: "Devam ediyor",
      className: "bg-sky-50 text-sky-800 border border-sky-200",
    },
    blocked: {
      label: "Blokaj var",
      className: "bg-amber-50 text-amber-800 border border-amber-200",
    },
    done: {
      label: "Tamamlandı",
      className: "bg-emerald-50 text-emerald-800 border border-emerald-200",
    },
  };

  const item = map[status];

  return (
    <span
      className={`inline-flex rounded-full px-2 py-0.5 text-[10px] font-medium ${item.className}`}
    >
      {item.label}
    </span>
  );
}

function PriorityBadge({ priority }: { priority: ProjectPriority }) {
  const map: Record<ProjectPriority, { label: string; className: string }> = {
    low: {
      label: "Düşük",
      className: "bg-slate-50 text-slate-700 border border-slate-200",
    },
    medium: {
      label: "Orta",
      className: "bg-indigo-50 text-indigo-800 border border-indigo-200",
    },
    high: {
      label: "Yüksek",
      className: "bg-rose-50 text-rose-800 border border-rose-200",
    },
  };

  const item = map[priority];

  return (
    <span
      className={`inline-flex rounded-full px-2 py-0.5 text-[10px] font-medium ${item.className}`}
    >
      {item.label}
    </span>
  );
}

"use client";

// app/project-hub/rfq/page.tsximport Link from "next/link";
import { useState, FormEvent } from "react";
import PageShell from "@/components/layout/PageShell";

type RfqItem = {
  id: number;
  customer: string;
  projectCode: string;
  partName: string;
  annualVolume: string;
  sopDate: string;
  qualityNotes: string;
  status: "Açık" | "Çalışılıyor" | "Kapatıldı";
};

type StatusFilter = "all" | RfqItem["status"];

const STATUS_OPTIONS: RfqItem["status"][] = [
  "Açık",
  "Çalışılıyor",
  "Kapatıldı",
];

let nextId = 1;

export default function RfqSummaryPage() {
  const [items, setItems] = useState<RfqItem[]>([]);
  const [statusFilter, setStatusFilter] = useState<StatusFilter>("all");

  const [form, setForm] = useState({
    customer: "",
    projectCode: "",
    partName: "",
    annualVolume: "",
    sopDate: "",
    qualityNotes: "",
    status: "Açık" as RfqItem["status"],
  });

  const [error, setError] = useState<string | null>(null);

  function handleChange<K extends keyof typeof form>(
    key: K,
    value: (typeof form)[K],
  ) {
    setForm((prev) => ({ ...prev, [key]: value }));
  }

  function handleAdd(e: FormEvent) {
    e.preventDefault();
    setError(null);

    if (!form.customer || !form.projectCode || !form.partName) {
      setError("Müşteri, Proje Kodu ve Parça alanları zorunludur.");
      return;
    }

    const newItem: RfqItem = {
      id: nextId++,
      customer: form.customer,
      projectCode: form.projectCode,
      partName: form.partName,
      annualVolume: form.annualVolume,
      sopDate: form.sopDate,
      qualityNotes: form.qualityNotes,
      status: form.status,
    };

    setItems((prev) => [newItem, ...prev]);

    // Formu kısmen sıfırlayalım
    setForm((prev) => ({
      ...prev,
      partName: "",
      annualVolume: "",
      sopDate: "",
      qualityNotes: "",
    }));
  }

  function handleDelete(id: number) {
    setItems((prev) => prev.filter((item) => item.id !== id));
  }

  function handleStatusChange(id: number, status: RfqItem["status"]) {
    setItems((prev) =>
      prev.map((item) => (item.id === id ? { ...item, status } : item)),
    );
  }

  const filteredItems =
    statusFilter === "all"
      ? items
      : items.filter((item) => item.status === statusFilter);

  return (
    <PageShell>
      {/* Baş kısım */}
      <section className="rounded-2xl border border-slate-200 bg-white p-5 shadow-sm">
        <div className="mb-3 flex items-center gap-2">
          <span className="rounded-full bg-slate-900 px-3 py-1 text-[10px] font-semibold uppercase tracking-wide text-white">
            Proje Mühendisleri Alanı
          </span>
          <span className="rounded-full bg-slate-100 px-3 py-1 text-[10px] font-medium text-slate-600">
            RFQ / Teknik Şartname Özeti
          </span>
        </div>

        <h1 className="text-lg font-semibold text-slate-900">
          RFQ / Teknik Şartname Özeti
        </h1>
        <p className="mt-2 text-xs text-slate-600">
          Müşteriden gelen RFQ ve teknik şartnameleri; müşteri, proje kodu, parça adı, hedef adet ve SOP bilgisi ile
          özetlemek için hafif bir takip ekranı. Girdiğin satırlar bu sayfada tutulur. PDF/Excel dışa aktarma premium
          paketinin özel beta kapsamındadır. Erken erişim için{" "}
          <Link href="/pricing" className="font-semibold text-amber-700 hover:underline">
            ücretlendirmeye göz at
          </Link>.
        </p>
      </section>

      {/* Form + Liste + Premium export alanı */}
      <section className="grid gap-4 lg:grid-cols-[minmax(0,1.4fr)_minmax(0,1fr)]">
        {/* Sol: RFQ formu */}
        <div className="rounded-2xl border border-slate-200 bg-white p-5 text-xs shadow-sm">
          <h2 className="mb-3 text-sm font-semibold text-slate-900">
            Yeni RFQ / Teknik Şartname Satırı
          </h2>

          <form className="space-y-3" onSubmit={handleAdd}>
            <div className="grid gap-2 sm:grid-cols-2">
              <div className="space-y-1">
                <label className="block text-[11px] font-medium text-slate-700">
                  Müşteri
                </label>
                <input
                  type="text"
                  value={form.customer}
                  onChange={(e) => handleChange("customer", e.target.value)}
                  className="w-full rounded-lg border border-slate-300 px-2 py-1.5 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
                  placeholder="Örn. OEM X, Tier1 Y"
                 aria-label="Örn. OEM X, Tier1 Y"/>
              </div>

              <div className="space-y-1">
                <label className="block text-[11px] font-medium text-slate-700">
                  Proje Kodu
                </label>
                <input
                  type="text"
                  value={form.projectCode}
                  onChange={(e) => handleChange("projectCode", e.target.value)}
                  className="w-full rounded-lg border border-slate-300 px-2 py-1.5 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
                  placeholder="Örn. P-2025-01"
                 aria-label="Örn. P-2025-01"/>
              </div>
            </div>

            <div className="space-y-1">
              <label className="block text-[11px] font-medium text-slate-700">
                Parça Adı / Kodu
              </label>
              <input
                type="text"
                value={form.partName}
                onChange={(e) => handleChange("partName", e.target.value)}
                className="w-full rounded-lg border border-slate-300 px-2 py-1.5 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
                placeholder="Örn. Ön amortisör üst bağlantı braketi"
               aria-label="Örn. Ön amortisör üst bağlantı braketi"/>
            </div>

            <div className="grid gap-2 sm:grid-cols-3">
              <div className="space-y-1">
                <label className="block text-[11px] font-medium text-slate-700">
                  Hedef adet / yıl
                </label>
                <input
                  type="text"
                  value={form.annualVolume}
                  onChange={(e) =>
                    handleChange("annualVolume", e.target.value)
                  }
                  className="w-full rounded-lg border border-slate-300 px-2 py-1.5 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
                  placeholder="Örn. 50.000"
                 aria-label="Örn. 50.000"/>
              </div>

              <div className="space-y-1">
                <label className="block text-[11px] font-medium text-slate-700">
                  Hedef SOP tarihi
                </label>
                <input
                  type="date"
                  value={form.sopDate}
                  onChange={(e) => handleChange("sopDate", e.target.value)}
                  className="w-full rounded-lg border border-slate-300 px-2 py-1.5 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
                 aria-label="Date input"/>
              </div>

              <div className="space-y-1">
                <label className="block text-[11px] font-medium text-slate-700">
                  Durum
                </label>
                <select
                  value={form.status}
                  onChange={(e) =>
                    handleChange("status", e.target.value as RfqItem["status"])
                  }
                  className="w-full rounded-lg border border-slate-300 px-2 py-1.5 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
                 aria-label="Select field">
                  {STATUS_OPTIONS.map((status) => (
                    <option key={status} value={status}>
                      {status}
                    </option>
                  ))}
                </select>
              </div>
            </div>

            <div className="space-y-1">
              <label className="block text-[11px] font-medium text-slate-700">
                Özel kalite / test notları
              </label>
              <textarea
                value={form.qualityNotes}
                onChange={(e) =>
                  handleChange("qualityNotes", e.target.value)
                }
                rows={3}
                className="w-full rounded-lg border border-slate-300 px-2 py-1.5 text-xs outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
                placeholder="Örn. Özel tuz testi, ek sızdırmazlık testi, müşteri şartnamesi XYZ-123'e referans..."
               aria-label="Örn. Özel tuz testi, ek sızdırmazlık testi, müşteri şartnamesi XYZ-123'e referans..."/>
            </div>

            {error && (
              <p className="text-[11px] text-red-600">
                {error}
              </p>
            )}

            <button
              type="submit"
              className="mt-2 inline-flex items-center rounded-full bg-slate-900 px-4 py-1.5 text-[11px] font-semibold text-white hover:bg-slate-800"
            >
              Satıra ekle
            </button>
          </form>
        </div>

        {/* Sağ: Liste + Premium export box */}
        <div className="space-y-4">
          {/* Liste */}
          <div className="rounded-2xl border border-slate-200 bg-white p-5 text-xs shadow-sm">
            <div className="mb-3 flex items-center justify-between">
              <h2 className="text-sm font-semibold text-slate-900">
                RFQ Listesi
              </h2>
              <StatusFilterChips
                value={statusFilter}
                onChange={setStatusFilter}
              />
            </div>

            {filteredItems.length === 0 ? (
              <p className="text-[11px] text-slate-500">
                Henüz kayıt yok. Soldaki formdan bir RFQ satırı ekleyebilirsin.
              </p>
            ) : (
              <div className="max-h-80 space-y-2 overflow-auto pr-1">
                {filteredItems.map((item) => (
                  <div
                    key={item.id}
                    className="rounded-xl border border-slate-200 bg-slate-50 px-3 py-2"
                  >
                    <div className="mb-1 flex items-center justify-between gap-2">
                      <div className="flex flex-col">
                        <span className="text-[11px] font-semibold text-slate-900">
                          {item.customer} – {item.projectCode}
                        </span>
                        <span className="text-[11px] text-slate-600">
                          {item.partName}
                        </span>
                      </div>
                      <span className="rounded-full bg-slate-900 px-2 py-0.5 text-[10px] font-semibold text-white">
                        {item.status}
                      </span>
                    </div>

                    <div className="mb-1 flex flex-wrap gap-x-3 gap-y-1 text-[11px] text-slate-600">
                      {item.annualVolume && (
                        <span>Hedef adet/yıl: {item.annualVolume}</span>
                      )}
                      {item.sopDate && (
                        <span>
                          Hedef SOP:{" "}
                          {new Date(item.sopDate).toLocaleDateString("tr-TR")}
                        </span>
                      )}
                    </div>

                    {item.qualityNotes && (
                      <p className="text-[11px] text-slate-600">
                        Not: {item.qualityNotes}
                      </p>
                    )}

                    <div className="mt-2 flex flex-wrap items-center justify-between gap-2">
                      <div className="flex items-center gap-2">
                        <span className="text-[10px] font-medium text-slate-600">
                          Durumu değiştir
                        </span>
                        <select
                          value={item.status}
                          onChange={(e) =>
                            handleStatusChange(
                              item.id,
                              e.target.value as RfqItem["status"],
                            )
                          }
                          className="rounded-lg border border-slate-300 bg-white px-2 py-1 text-[10px] text-slate-700 outline-none focus:border-slate-900 focus:ring-1 focus:ring-slate-900/40"
                         aria-label="Select field">
                          {STATUS_OPTIONS.map((status) => (
                            <option key={status} value={status}>
                              {status}
                            </option>
                          ))}
                        </select>
                      </div>
                      <button
                        type="button"
                        onClick={() => handleDelete(item.id)}
                        className="text-[11px] text-red-600 hover:underline"
                      >
                        Sil
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Premium export kutusu */}
