  let statusMessage = "";
  if (stress === 0) {
    statusMessage = "Hesaplama için değer giriniz.";
  } else if (safetyFactor >= 2) {
    statusMessage = "Durum: Emniyette (n ≥ 2).";
  } else if (safetyFactor >= 1.2) {
    statusMessage = "Durum: Sınırda (1.2 ≤ n < 2).";
  } else {
    statusMessage = "Durum: Riskli (n < 1.2).";
  }

  return (
    <PageShell>
