        {/* INPUT ALANI */}
        <div className="space-y-4">
          {/* Kuvvet */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Kuvvet (N)
            </label>
            <input
              type="number"
              className="w-full border p-2 rounded"
              value={force}
              onChange={(e) => setForce(Number(e.target.value))}
              placeholder="ör. 5000"
             aria-label="ör. 5000"/>
          </div>

          {/* Alan */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Kesit Alanı (mm²)
            </label>
            <input
              type="number"
              className="w-full border p-2 rounded"
              value={area}
              onChange={(e) => setArea(Number(e.target.value))}
              placeholder="ör. 100"
             aria-label="ör. 100"/>
          </div>

          {/* Malzeme */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Malzeme
            </label>
            <select
              className="w-full border p-2 rounded"
              value={material}
              onChange={(e) => setMaterial(e.target.value)}
             aria-label="Select field">
              {MATERIALS.map((m) => (
                <option key={m.name} value={m.name}>
                  {m.name}
                </option>
              ))}
            </select>
          </div>
        </div>

        {/* SONUÇLAR */}
        <div className="mt-6 border-t pt-4">
          <h2 className="text-lg font-semibold mb-2">Sonuçlar</h2>

          <p className="text-sm mb-1">
            <strong>Gerilme (σ): </strong>
            {stress.toFixed(2)} MPa
          </p>

          <p className="text-sm mb-1">
            <strong>Akma Dayanımı (Re): </strong>
            {selectedMaterial.yieldStrength} MPa
          </p>

          <p className="text-sm mb-3">
            <strong>Emniyet Katsayısı (n): </strong>
            {safetyFactor > 0 ? safetyFactor.toFixed(2) : "-"}
